import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { signOut, auth } from './firebase';

function NavBar({ isAuthenticated, setIsAuthenticated }) {
  const navigate = useNavigate();

  const handleLogout = async () => {
    await signOut(auth);
    setIsAuthenticated(false);
    navigate('/login');
  };
  return (
    <nav style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '16px 24px', background: '#1976d2', color: '#fff', borderRadius: '8px 8px 0 0', marginBottom: 24 }}>
      <div style={{ display: 'flex', gap: '18px', fontWeight: 500 }}>
        <span style={{ fontWeight: 700, fontSize: '1.3rem', letterSpacing: '1px' }}>OLINEY</span>
        <Link to="/bills" style={{ color: '#fff', textDecoration: 'none', marginLeft: 16 }}>홈</Link>
        {isAuthenticated && <Link to="/bill" style={{ color: '#fff', textDecoration: 'none' }}>청구서 제작</Link>}
        {isAuthenticated && <Link to="/mybills" style={{ color: '#fff', textDecoration: 'none' }}>내 청구서</Link>}
      </div>
      <div>
        {!isAuthenticated ? (
          <Link to="/login" style={{ color: '#fff', textDecoration: 'none', fontWeight: 500 }}>로그인</Link>
        ) : (
          <button onClick={handleLogout} style={{ background: '#fff', border: 'none', color: '#1976d2', fontWeight: 500, borderRadius: 4, padding: '6px 16px', cursor: 'pointer' }}>로그아웃</button>
        )}
      </div>
    </nav>
  );
}

export default NavBar;
