import React, { useState } from 'react';
import { db, auth } from './firebase';
import { collection, addDoc } from 'firebase/firestore';

const BANKS = [
  '국민', '신한', '우리', '하나', '농협', '카카오', '기업', 'SC제일', '씨티', '부산', '경남', '대구', '광주', '수협', '우체국', '새마을', '신협', '산업', '전북', '제주',
  '케이뱅크', '토스뱅크', '저축은행', '한국은행', '중앙', '상호저축', '산림조합', 'HSBC', 'JP모간', 'BOA', 'BNP파리바', '도이치', '중국은행', '중국공상', '중국건설', '중국교통', '중국농업', '신용협동조합', '기타'
];

function maskOwner(name) {
  // 짝수 자리 글자만 *로 마스킹
  return name.split('').map((ch, i) => (i % 2 === 1 ? '*' : ch)).join('');
}

function BillForm() {
  const [items, setItems] = useState([
    { title: '', amount: '', desc: '' }
  ]);
  const [bank, setBank] = useState(BANKS[0]);
  const [customBank, setCustomBank] = useState('');
  const [account, setAccount] = useState('');
  const [owner, setOwner] = useState('');
  const [link, setLink] = useState('');
  const [loading, setLoading] = useState(false);

  // 항목 추가
  const addItem = () => {
    setItems([...items, { title: '', amount: '', desc: '' }]);
  };

  // 항목 삭제
  const removeItem = idx => {
    if (items.length === 1) return;
    setItems(items.filter((_, i) => i !== idx));
  };

  // 항목 값 변경
  const handleChange = (idx, field, value) => {
    const newItems = items.map((item, i) =>
      i === idx ? { ...item, [field]: value } : item
    );
    setItems(newItems);
  };

  // 소유주 이름 입력 시 원본 값 저장
  const handleOwnerChange = (e) => {
    setOwner(e.target.value);
  };

  // 저장
  const handleSubmit = async e => {
    e.preventDefault();
    if (items.some(item => !item.title || !item.amount)) {
      alert('모든 항목의 제목과 금액을 입력하세요.');
      return;
    }
    if (!account || !owner) {
      alert('계좌번호와 소유주 이름을 입력하세요.');
      return;
    }
    const bankToSave = bank === '기타' ? customBank : bank;
    if (bank === '기타' && !customBank) {
      alert('기타 은행명을 입력하세요.');
      return;
    }
    setLoading(true);
    try {
      const user = auth.currentUser;
      const docRef = await addDoc(collection(db, 'bills'), {
        items,
        bank: bank === '기타' ? customBank : bank,
        account,
        owner: maskOwner(owner),
        createdAt: new Date().toISOString(),
        uid: user ? user.uid : null,
        email: user ? user.email : null,
        status: '대기'
      });
      const billLink = `${window.location.origin}/view/${docRef.id}`;
      setLink(billLink);
      setItems([{ title: '', amount: '', desc: '' }]);
      setAccount('');
      setOwner('');
      setBank(BANKS[0]);
      setCustomBank('');
    } catch (err) {
      alert('청구서 저장에 실패했습니다.');
    }
    setLoading(false);
  };

  // 링크 복사
  const handleCopy = () => {
    if (link) {
      navigator.clipboard.writeText(link);
      alert('링크가 복사되었습니다! 상대방에게 전송하세요.');
    }
  };

  return (
    <div style={{ maxWidth: 480, margin: '0 auto', background: '#f9f9fb', borderRadius: 12, boxShadow: '0 2px 12px #eee', padding: 32 }}>
      <h2 style={{ color: '#1976d2', fontWeight: 700, marginBottom: 24 }}>청구서 제작</h2>
      <form onSubmit={handleSubmit}>
        {/* 항목 입력 카드 */}
        {items.map((item, idx) => (
          <div key={idx} style={{ background: '#fff', borderRadius: 8, boxShadow: '0 1px 4px #e0e0e0', padding: 16, marginBottom: 16, position: 'relative' }}>
            <div style={{ display: 'flex', gap: 12, marginBottom: 8 }}>
              <input
                type="text"
                placeholder="항목 제목"
                value={item.title}
                onChange={e => handleChange(idx, 'title', e.target.value)}
                style={{ flex: 2, padding: 8, borderRadius: 4, border: '1px solid #ccc' }}
              />
              <input
                type="number"
                placeholder="금액"
                value={item.amount}
                onChange={e => handleChange(idx, 'amount', e.target.value)}
                style={{ flex: 1, padding: 8, borderRadius: 4, border: '1px solid #ccc' }}
              />
            </div>
            <input
              type="text"
              placeholder="설명 (선택)"
              value={item.desc}
              onChange={e => handleChange(idx, 'desc', e.target.value)}
              style={{ width: '100%', padding: 8, borderRadius: 4, border: '1px solid #ccc', marginBottom: 8 }}
            />
            {items.length > 1 && (
              <button type="button" onClick={() => removeItem(idx)} style={{ position: 'absolute', top: 12, right: 12, background: '#eee', border: 'none', borderRadius: 4, padding: '2px 8px', cursor: 'pointer', color: '#888' }}>삭제</button>
            )}
          </div>
        ))}
        <button type="button" onClick={addItem} style={{ background: '#1976d2', color: '#fff', border: 'none', borderRadius: 6, padding: '8px 18px', fontWeight: 500, marginBottom: 16, cursor: 'pointer' }}>항목 추가</button>
        {/* 은행/계좌/소유주 입력 */}
        <div style={{ background: '#fff', borderRadius: 8, boxShadow: '0 1px 4px #e0e0e0', padding: 16, marginBottom: 16 }}>
          <div style={{ marginBottom: 12 }}>
            <label style={{ marginRight: 8 }}>은행사:</label>
            <select value={bank} onChange={e => setBank(e.target.value)} style={{ padding: 6, borderRadius: 4, border: '1px solid #ccc' }}>
              {BANKS.map(b => <option key={b} value={b}>{b}</option>)}
            </select>
            {bank === '기타' && (
              <input type="text" value={customBank} onChange={e => setCustomBank(e.target.value)} placeholder="은행명 입력" style={{ marginLeft: 12, padding: 6, borderRadius: 4, border: '1px solid #ccc', width: 120 }} />
            )}
          </div>
          <div style={{ marginBottom: 12 }}>
            <label style={{ marginRight: 8 }}>계좌번호:</label>
            <input type="text" value={account} onChange={e => setAccount(e.target.value)} style={{ padding: 6, borderRadius: 4, border: '1px solid #ccc', width: 180 }} />
          </div>
          <div>
            <label style={{ marginRight: 8 }}>소유주 이름:</label>
            <input type="text" value={owner} onChange={handleOwnerChange} style={{ padding: 6, borderRadius: 4, border: '1px solid #ccc', width: 120 }} />
          </div>
        </div>
        <button type="submit" disabled={loading} style={{ background: '#1976d2', color: '#fff', border: 'none', borderRadius: 6, padding: '10px 32px', fontWeight: 700, fontSize: 16, cursor: 'pointer' }}>
          {loading ? '저장 중...' : '청구서 제작'}
        </button>
      </form>
      {/* 링크 공유 섹션 */}
      {link && (
        <div style={{ marginTop: 32, textAlign: 'center' }}>
          <div style={{ fontWeight: 500, marginBottom: 8 }}>청구서 링크:</div>
          <input type="text" value={link} readOnly style={{ width: '100%', marginBottom: 8, padding: 8, borderRadius: 4, border: '1px solid #ccc' }} />
          <button onClick={handleCopy} style={{ background: '#1976d2', color: '#fff', border: 'none', borderRadius: 6, padding: '8px 18px', fontWeight: 500, cursor: 'pointer' }}>링크 복사</button>
          <div style={{ marginTop: 8, color: '#1976d2' }}>
            복사된 링크를 상대방에게 전송하세요!
          </div>
        </div>
      )}
    </div>
  );
}

export default BillForm;
