import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { db, auth } from './firebase';
import { doc, getDoc, updateDoc, deleteDoc } from 'firebase/firestore';
import BillForm from './BillForm';

function formatDate(dateStr) {
  if (!dateStr) return '';
  const d = new Date(dateStr);
  const yyyy = d.getFullYear();
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  const hh = String(d.getHours()).padStart(2, '0');
  const min = String(d.getMinutes()).padStart(2, '0');
  return `${yyyy}-${mm}-${dd} ${hh}:${min}`;
}

function BillView() {
  const { id } = useParams();
  const [bill, setBill] = useState(null);
  const [loading, setLoading] = useState(true);
  const [included, setIncluded] = useState([]);
  const [showAccount, setShowAccount] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [editData, setEditData] = useState(null);
  const user = auth.currentUser;
  const navigate = useNavigate();

  useEffect(() => {
    async function fetchBill() {
      setLoading(true);
      const docRef = doc(db, 'bills', id);
      const docSnap = await getDoc(docRef);
      if (docSnap.exists()) {
        setBill(docSnap.data());
        setIncluded(docSnap.data().items ? docSnap.data().items.map(() => true) : []);
      } else {
        setBill(null);
      }
      setLoading(false);
    }
    fetchBill();
  }, [id]);

  if (loading) return <div>불러오는 중...</div>;
  if (!bill || !bill.items) return <div>청구서를 찾을 수 없습니다.</div>;

  // 입금 상태 변경
  const handleStatusChange = async (newStatus) => {
    const docRef = doc(db, 'bills', id);
    await updateDoc(docRef, { status: newStatus });
    setBill(prev => ({ ...prev, status: newStatus }));
  };

  const handleToggle = idx => {
    setIncluded(prev => prev.map((v, i) => (i === idx ? !v : v)));
  };

  const total = bill.items.reduce((sum, item, idx) => sum + (included[idx] ? Number(item.amount) : 0), 0);

  // 로그인 유저가 청구서 작성자는지 여부
  const isOwner = user && bill && user.uid === bill.uid;

  // 수정 버튼 클릭 시
  const handleEdit = () => {
    setEditData({
      items: bill.items,
      bank: bill.bank,
      account: bill.account,
      owner: bill.owner,
      id,
      customBank: bill.bank,
    });
    setEditMode(true);
  };

  // 수정 저장
  const handleEditSave = async (newData) => {
    const docRef = doc(db, 'bills', id);
    await updateDoc(docRef, {
      items: newData.items,
      bank: newData.bank,
      account: newData.account,
      owner: newData.owner,
      updatedAt: new Date().toISOString(),
    });
    setBill(prev => ({ ...prev, ...newData, updatedAt: new Date().toISOString() }));
    setEditMode(false);
  };

  // 삭제
  const handleDelete = async () => {
    if (window.confirm('정말 삭제하시겠습니까?')) {
      await deleteDoc(doc(db, 'bills', id));
      alert('청구서가 삭제되었습니다.');
      navigate('/mybills');
    }
  };

  if (editMode) {
    // BillForm을 수정 모드로 렌더링하며 기존 청구서 내용을 initialData로 전달
    return (
      <BillForm
        initialData={editData}
        onSave={handleEditSave}
        onCancel={() => setEditMode(false)}
        isEditMode={true}
      />
    );
  }

  return (
    <div style={{ maxWidth: 480, margin: '0 auto', background: '#f9f9fb', borderRadius: 12, boxShadow: '0 2px 12px #eee', padding: 32 }}>
      <h2 style={{ color: '#1976d2', fontWeight: 700, marginBottom: 24 }}>청구서 열람</h2>
      <div style={{ marginBottom: 12, fontWeight: 500, color: '#555' }}>
        작성일: <span style={{ fontWeight: 600 }}>{formatDate(bill.createdAt)}</span><br />
        작성자: <span style={{ fontWeight: 600 }}>{bill.email}</span><br />
        입금 상태: <span style={{ fontWeight: 600, color: bill.status === '완료' ? 'green' : bill.status === '취소' ? 'red' : '#1976d2' }}>{bill.status || '대기'}</span>
      </div>
      {/* 입금 상태 변경 버튼: 로그인 유저만 표시 */}
      {user && (
        <div style={{ marginBottom: 16 }}>
          <button onClick={() => handleStatusChange('완료')} disabled={bill.status === '완료'} style={{ background: '#43a047', color: '#fff', border: 'none', borderRadius: 6, padding: '8px 18px', fontWeight: 500, cursor: bill.status === '완료' ? 'not-allowed' : 'pointer', marginRight: 8 }}>
            입금 완료
          </button>
          <button onClick={() => handleStatusChange('취소')} disabled={bill.status === '취소'} style={{ background: '#e53935', color: '#fff', border: 'none', borderRadius: 6, padding: '8px 18px', fontWeight: 500, cursor: bill.status === '취소' ? 'not-allowed' : 'pointer' }}>
            입금 취소
          </button>
        </div>
      )}
      {/* 본인 청구서일 경우 삭제 버튼만 노출 */}
      {isOwner && (
        <div style={{ marginBottom: 16 }}>
          <button onClick={handleDelete} style={{ background: '#e53935', color: '#fff', border: 'none', borderRadius: 6, padding: '8px 18px', fontWeight: 500 }}>삭제</button>
        </div>
      )}
      {bill.items.map((item, idx) => (
        <div key={idx} style={{ background: '#fff', borderRadius: 8, boxShadow: '0 1px 4px #e0e0e0', padding: 16, marginBottom: 16, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <div style={{ textAlign: 'left', flex: 1 }}>
            <div style={{ fontWeight: 600, fontSize: '1.1rem', marginBottom: 6 }}>{item.title}</div>
            <div style={{ color: '#1976d2', fontWeight: 700, fontSize: '1.1rem' }}>{item.amount}원</div>
            {item.desc && <div style={{ color: '#888', marginTop: 6 }}>{item.desc}</div>}
          </div>
          <div style={{ marginLeft: 16 }}>
            <label style={{ fontSize: 13, color: '#1976d2', fontWeight: 500 }}>
              합계 포함
              <input type="checkbox" checked={included[idx]} onChange={() => handleToggle(idx)} style={{ marginLeft: 6 }} />
            </label>
          </div>
        </div>
      ))}
      <div style={{ fontWeight: 700, fontSize: '1.2rem', color: '#1976d2', marginTop: 24 }}>
        총 합계: {total}원
      </div>
      <div style={{ marginTop: 32 }}>
        <button onClick={() => setShowAccount(v => !v)} style={{ background: '#1976d2', color: '#fff', border: 'none', borderRadius: 6, padding: '8px 18px', fontWeight: 500, cursor: 'pointer', width: '100%' }}>
          {showAccount ? '계좌 정보 닫기' : '계좌 정보 보기'}
        </button>
        {showAccount && (
          <div style={{ background: '#fff', borderRadius: 8, boxShadow: '0 1px 4px #e0e0e0', padding: 16, marginTop: 8 }}>
            <div style={{ fontWeight: 500, marginBottom: 8 }}>입금 계좌 정보</div>
            <div>은행사: <span style={{ fontWeight: 600 }}>{bill.bank}</span></div>
            <div>계좌번호: <span style={{ fontWeight: 600 }}>{bill.account}</span></div>
            <div>소유주: <span style={{ fontWeight: 600 }}>{bill.owner}</span></div>
          </div>
        )}
      </div>
    </div>
  );
}

export default BillView;
