import React, { useEffect, useState } from 'react';
import { db, auth } from './firebase';
import { collection, query, where, getDocs } from 'firebase/firestore';
import { Link } from 'react-router-dom';

function MyBills() {
  const [bills, setBills] = useState([]);
  const [loading, setLoading] = useState(true);
  const user = auth.currentUser;

  useEffect(() => {
    async function fetchBills() {
      if (!user) return;
      setLoading(true);
      const q = query(collection(db, 'bills'), where('uid', '==', user.uid));
      const querySnapshot = await getDocs(q);
      const billsArr = [];
      querySnapshot.forEach(doc => {
        billsArr.push({ id: doc.id, ...doc.data() });
      });
      setBills(billsArr);
      setLoading(false);
    }
    fetchBills();
  }, [user]);

  if (!user) return <div>로그인 후 이용 가능합니다.</div>;
  if (loading) return <div>불러오�� 중...</div>;

  return (
    <div style={{ maxWidth: 480, margin: '0 auto', padding: 32 }}>
      <h2 style={{ color: '#1976d2', fontWeight: 700, marginBottom: 24 }}>내 청구서 목록</h2>
      {bills.length === 0 ? (
        <div>작성한 청구서가 없습니다.</div>
      ) : (
        <ul style={{ listStyle: 'none', padding: 0 }}>
          {bills.map(bill => (
            <li key={bill.id} style={{ background: '#fff', borderRadius: 8, boxShadow: '0 1px 4px #e0e0e0', padding: 16, marginBottom: 16 }}>
              <div style={{ fontWeight: 600 }}>{bill.items && bill.items[0] ? bill.items[0].title : '청구서'}</div>
              <div style={{ color: '#888', fontSize: 13 }}>작성일: {bill.createdAt ? bill.createdAt.slice(0, 16).replace('T', ' ') : ''}</div>
              <div style={{ color: bill.status === '완료' ? 'green' : bill.status === '취소' ? 'red' : '#1976d2', fontWeight: 500 }}>상태: {bill.status || '대기'}</div>
              <Link to={`/view/${bill.id}`} style={{ color: '#1976d2', textDecoration: 'underline', marginTop: 8, display: 'inline-block' }}>상세보기</Link>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

export default MyBills;

