import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Login from './Login';
import BillForm from './BillForm';
import BillView from './BillView';
import BillList from './BillList';
import NavBar from './NavBar';
import MyBills from './MyBills';
import { auth } from './firebase';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [bills, setBills] = useState([
    { id: 1, title: '예시 청구서', amount: 10000, desc: '샘플 설명' }
  ]);

  useEffect(() => {
    const unsubscribe = auth.onAuthStateChanged(user => {
      setIsAuthenticated(!!user);
    });
    return () => unsubscribe();
  }, []);

  return (
    <Router>
      <div className="App" style={{ maxWidth: 600, margin: '40px auto', background: '#fff', borderRadius: 8, boxShadow: '0 2px 8px #eee', padding: 24 }}>
        <NavBar isAuthenticated={isAuthenticated} setIsAuthenticated={setIsAuthenticated} />
        <Routes>
          <Route path="/login" element={<Login setIsAuthenticated={setIsAuthenticated} />} />
          <Route path="/bill" element={isAuthenticated ? <BillForm setBills={setBills} bills={bills} /> : <Navigate to="/login" />} />
          <Route path="/view/:id" element={<BillView bills={bills} />} />
          <Route path="/bills" element={<BillList bills={bills} />} />
          <Route path="/mybills" element={<MyBills />} />
          <Route path="/" element={<Navigate to="/bills" />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
